package be.schaubroeck.lpb.rkm.rekenmotor.bruto;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonCodeCalculator;
import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.RkmCoreHrConfiguratie;
import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.service.BijdragePercentagesFactory;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.Indexator;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonCodeManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.rkm.rekenmotor.util.TimeTools;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Constant;
import be.schaubroeck.lpb.tools.LooncodeInclusief;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.Vergoeding;
import be.schaubroeck.lpb.tools.enumtypes.AardKodeExt;
import be.schaubroeck.lpb.tools.enumtypes.AkeTijdperk;
import be.schaubroeck.lpb.tools.enumtypes.CstEenheid;
import be.schaubroeck.lpb.tools.enumtypes.Janeen;
import be.schaubroeck.lpb.tools.enumtypes.KedefFormuletype;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.jpa.gl.LooncodeInclusiefPK;
import be.schaubroeck.lpb.tools.jpa.gl.LooncodeInclusiefPO;
import be.schaubroeck.lpb.tools.service.LooncodeInclusiefService;
import com.google.common.collect.ImmutableList;
import com.google.common.collect.ImmutableSet;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey.BRUTO_MAANDLOON_KEY;

public abstract class AbstractLoonCodeCalculator implements LoonCodeCalculator {

    protected final LoonCodeCalculatorFactory factory;

    protected final ConstantManager constantManager;
    protected final RegulManager regulManager;
    protected final AardKodeExtensie aardKodeExtensie;
    protected final LoonCodeManager loonCodeManager;
    protected final BijdragePercentagesFactory bijdragePercentagesFactory;
    protected final LooncodeInclusiefService looncodeInclusiefService;
    private final RkmCoreHrConfiguratie rkmCoreHrConfiguratie;

    protected final SleutelGegevens gegevens;
    protected final RekenTijd rekenTijd;

    protected final Set<LoonElement> supplementenFase1;
    protected final BigDecimal index;

    protected boolean zonderToeslag = false;

    protected AbstractLoonCodeCalculator(
            SleutelGegevens gegevens, AardKodeExtensie aardKodeExtensie, RekenTijd rekenTijd,
            LoonCodeCalculatorFactory factory, Set<LoonElement> supplementenFase1, BigDecimal index) {
        this.aardKodeExtensie = aardKodeExtensie;
        this.loonCodeManager = factory.getLoonCodeManager();
        this.bijdragePercentagesFactory = factory.getBijdragePercentagesFactory();
        this.looncodeInclusiefService = factory.getLooncodeInclusiefService();
        this.rkmCoreHrConfiguratie = factory.getRkmCoreHrConfiguratie();
        this.gegevens = gegevens;
        this.constantManager = factory.getConstantManager();
        this.regulManager = factory.getRegulManager();
        this.rekenTijd = rekenTijd;
        this.factory = factory;
        this.supplementenFase1 = supplementenFase1;
        this.index = index;

    }

    public Money basisBedrag() {
        return basisBedrag(false);
    }

    private static final BigDecimal FACTOR_COMPLEMENT_VIER_DAGEN_WEEK = new BigDecimal("0.8");// 4 op 5

    private static final int CODE_ARBEIDSDUURVERMINDERING_AKE = 853;

    private static final Set<Integer> CODES_MET_EXTRA_INCLUSIEF_CODES = ImmutableSet.of(401, 435, 436, 437, 510, 512, 801, 835, 836, 837, 910, 912);
    private static final Set<Integer> CODES_MET_EXTRA_INCLUSIEF_CODES_2025 = ImmutableSet.of(101, 434, 834);

    private static final LocalDate AUGUST_2025 = new LocalDate(2025, 8, 1);

    public Money basisBedrag(boolean hasta) {
        Money basisBedrag = gegevens.getJaarWedde().add(gegevens.getSalarisverhoging());
        if (hasta && isHastaZonderInclusiefCodes()) {
            return basisBedrag;
        }

        boolean premieHastaAdv =
                constantManager.getByCodeDatum(Konstanten.KST_PREMIE_ADV_HASTA, TimeTools.getZoekDatum(gegevens, rekenTijd.rekenPeriode)).getInteger()
                        .equals(Janeen.JA.getCode());
        BigDecimal prestatieVerhouding = RkmPrestatieVerhouding.bepaal(gegevens, regulManager);
        if (prestatieVerhouding.signum() == 0) {
            prestatieVerhouding = BigDecimal.ONE;
        }
        List<LooncodeInclusief> teIncluderenCodesList = looncodeInclusiefService.findByAardKodeExtensie(aardKodeExtensie);
        Set<LooncodeInclusief> teIncluderenCodes = new HashSet<>(teIncluderenCodesList);
        boolean isSupplementFase2 = aardKodeExtensie.getFormuleType() == KedefFormuletype.ONR_WG_UL && aardKodeExtensie.getConst3nr() != 0;
        List<LooncodeInclusief> extraInclusiefCodes = ImmutableList.of();
        if (aardKodeExtensie.getAard().equals(AardKodeExt.S_KODE_EXT.getCode()) && codesMetExtraInclusiefCodes()) {
            extraInclusiefCodes = ImmutableList
                    .of(mockLoonCodeInclusief(424, 1), mockLoonCodeInclusief(424, 2), mockLoonCodeInclusief(424, 3), mockLoonCodeInclusief(824, 1),
                            mockLoonCodeInclusief(824, 2), mockLoonCodeInclusief(824, 3), mockLoonCodeInclusief(824, 7), mockLoonCodeInclusief(824, 10),
                            mockLoonCodeInclusief(834, 170), mockLoonCodeInclusief(834, 171), mockLoonCodeInclusief(824, 11), mockLoonCodeInclusief(824, 12),
                            mockLoonCodeInclusief(824, 13), mockLoonCodeInclusief(824, 14), mockLoonCodeInclusief(824, 15), mockLoonCodeInclusief(824, 16),
                            mockLoonCodeInclusief(824, 18));
            teIncluderenCodes.addAll(extraInclusiefCodes);
        }
        Set<Vergoeding> vergoedingen = gegevens.getVergoedingen();
        for (LooncodeInclusief inclusiefCode : teIncluderenCodes) {
            for (Vergoeding vergoeding : vergoedingen) {
                if (isVergoedingInclusiefCodeMatch(vergoeding, inclusiefCode) && (!hasta || premieHastaAdv
                        || vergoeding.getCode() != CODE_ARBEIDSDUURVERMINDERING_AKE)) {
                    AardKodeExtensie inclusiefLoonCode = loonCodeManager.getByVergoeding(vergoeding);
                    LoonCodeCalculator inclusiefCalculator = factory.genereerLoonCodeCalculator(gegevens, inclusiefLoonCode, rekenTijd);
                    Money bedrag100Percent = inclusiefCalculator.berekenBedrag100Percent(vergoeding.getBedragWerknemer());
                    if (hasta && isComplementVierDagenWeek(inclusiefLoonCode)) {
                        bedrag100Percent = bedrag100Percent.multiply(FACTOR_COMPLEMENT_VIER_DAGEN_WEEK);
                    }
                    basisBedrag = basisBedrag.add(bedrag100Percent.round(2));
                }
            }
        }
        if (isSupplementFase2 && codesMetExtraInclusiefCodes()) {
            for (LooncodeInclusief inclusiefCode : extraInclusiefCodes) {
                for (LoonElement supplement : supplementenFase1) {
                    AardKodeExtensie supplementCode = supplement.getAardKodeExtensie();
                    if (isLoonCodeInclusiefCodeMatch(supplementCode, inclusiefCode)) {
                        Opper opper = supplement.getOpper();
                        Money bruto = supplement.getPropertyMoney(BRUTO_MAANDLOON_KEY);
                        bruto = bruto.multiply(RekenTools.TWELVE);
                        bruto = Indexator.deIndexeer(index, bruto, supplementCode, opper, true).round(2);
                        bruto = bruto.divide(prestatieVerhouding);
                        basisBedrag = basisBedrag.add(bruto);
                    }
                }
            }
        }
        return basisBedrag;
    }

    private boolean codesMetExtraInclusiefCodes() {
        return CODES_MET_EXTRA_INCLUSIEF_CODES.contains(aardKodeExtensie.getCode()) || codesMetExtraInclusiefCodesVanaf2025();
    }

    private boolean codesMetExtraInclusiefCodesVanaf2025() {
        return !rekenTijd.beginDatum.isBefore(AUGUST_2025) && CODES_MET_EXTRA_INCLUSIEF_CODES_2025.contains(aardKodeExtensie.getCode()) &&
                aardKodeExtensie.getFormuleType() == KedefFormuletype.ONR_WG_UL && isConst2Percentage(aardKodeExtensie);
    }

    private boolean isConst2Percentage(AardKodeExtensie aardKodeExtensie) {
        Constant const2 = constantManager.getByCodeDatum(aardKodeExtensie.getConst2nr(), rekenTijd.beginDatum);
        return const2.getEenheid() == CstEenheid.PCTFACTOR;
    }

    private boolean isHastaZonderInclusiefCodes() {
        return isGeenInclusiefCodeHastaLimaConf() || isGeenInclusiefCodeHastaConstantConf();
    }

    private boolean isGeenInclusiefCodeHastaLimaConf() {
        return rkmCoreHrConfiguratie != null && rkmCoreHrConfiguratie.isGeenInclusiefCodeHasta();
    }

    private boolean isGeenInclusiefCodeHastaConstantConf() {
        Constant cstGeenInclusiefCodeHasta = constantManager.getByCodeDatum(Konstanten.CST_GEEN_INCLUSIEFCODE_HGST, rekenTijd.beginDatum);
        return rkmCoreHrConfiguratie == null && cstGeenInclusiefCodeHasta != null && cstGeenInclusiefCodeHasta.getInteger() == 1;
    }

    private LooncodeInclusief mockLoonCodeInclusief(int inclusiefCode, int inclusiefExtensie) {
        LooncodeInclusief mock = new LooncodeInclusiefPO();
        mock.setId(new LooncodeInclusiefPK());
        mock.setTijdperk(aardKodeExtensie.getTijdperk());
        mock.setAard(aardKodeExtensie.getAard());
        mock.setCode(aardKodeExtensie.getCode());
        mock.setExtensie(aardKodeExtensie.getExtensie());

        mock.setInclusieVergoedingCode(inclusiefCode);
        mock.setInclusieVergoedingExtensie(inclusiefExtensie);
        return mock;
    }

    private boolean isLoonCodeInclusiefCodeMatch(AardKodeExtensie vergoeding, LooncodeInclusief inclusiefCode) {
        return
                (vergoeding.getTijdperk().equals(inclusiefCode.getTijdperk()) && vergoeding.getCode().equals(inclusiefCode.getInclusieVergoedingCode()))
                        && (!vergoeding.getExtensie().equals(aardKodeExtensie.getExtensie()) || !vergoeding.getCode().equals(aardKodeExtensie.getCode())) && (
                        inclusiefCode.getInclusieVergoedingExtensie() == 0 || vergoeding.getExtensie().equals(inclusiefCode.getInclusieVergoedingExtensie()));
    }

    private boolean isVergoedingInclusiefCodeMatch(Vergoeding vergoeding, LooncodeInclusief inclusiefCode) {
        return
                (vergoeding.getTijdperk().equals(inclusiefCode.getTijdperk()) && vergoeding.getCode().equals(inclusiefCode.getInclusieVergoedingCode()))
                        && (!vergoeding.getExtensie().equals(aardKodeExtensie.getExtensie()) || !vergoeding.getCode().equals(aardKodeExtensie.getCode())) && (
                        inclusiefCode.getInclusieVergoedingExtensie() == 0 || vergoeding.getExtensie().equals(inclusiefCode.getInclusieVergoedingExtensie()));
    }

    private boolean isComplementVierDagenWeek(AardKodeExtensie loonCode) {
        return (loonCode.getTijdperk().intValue() == AkeTijdperk.DMFAPPL.getCode() && loonCode.getCode() == 851 && loonCode.getExtensie() == 1) || (
                loonCode.getTijdperk().intValue() == AkeTijdperk.RSZPPO.getCode() && loonCode.getCode() == 451 && loonCode.getExtensie() == 1);
    }

    @Override
    public void setZonderToeslag(boolean zonderToeslag) {
        this.zonderToeslag = zonderToeslag;
    }

    @Override
    public boolean getZonderToeslag() {
        return zonderToeslag;
    }
}
